     1→import type { StateCreator } from 'zustand';
     2→import type { MarketplaceActions, MarketplaceState } from '../models';
     3→import { MarketplaceStatus } from '../models';
     4→
     5→export type MarketplaceSlice = {
     6→  marketplace: MarketplaceState;
     7→  marketplaceActions: MarketplaceActions;
     8→};
     9→
    10→const initialMarketplaceState: MarketplaceState = {
    11→  status: MarketplaceStatus.IDLE,
    12→  data: null,
    13→  error: undefined,
    14→};
    15→
    16→export const createMarketplaceSlice: StateCreator<
    17→  MarketplaceSlice,
    18→  [],
    19→  [],
    20→  MarketplaceSlice
    21→> = set => ({
    22→  marketplace: initialMarketplaceState,
    23→  marketplaceActions: {
    24→    setStatus: status =>
    25→      set(state => ({
    26→        marketplace: {
    27→          ...state.marketplace,
    28→          status,
    29→          ...(status === MarketplaceStatus.LOADING && {
    30→            error: undefined,
    31→          }),
    32→        },
    33→      })),
    34→    setData: data =>
    35→      set(state => ({
    36→        marketplace: {
    37→          ...state.marketplace,
    38→          data,
    39→          status: MarketplaceStatus.SUCCESS,
    40→          error: undefined,
    41→        },
    42→      })),
    43→    setError: error =>
    44→      set(state => ({
    45→        marketplace: {
    46→          ...state.marketplace,
    47→          error,
    48→        },
    49→      })),
    50→    reset: () =>
    51→      set({
    52→        marketplace: initialMarketplaceState,
    53→      }),
    54→  },
    55→});
    56→

